import { AppBar, Avatar, Badge, Drawer, Hidden, IconButton, List, Menu, ListItem, ListItemText, makeStyles, MenuItem, Toolbar, Tooltip, Typography, Box } from '@material-ui/core'
import { AddCircle, ExpandMore, MenuRounded, ViewModule } from '@material-ui/icons';
import phil from '../images/phil.png'
import logo4 from '../images/logo4.png'
import React from 'react';
import { withStyles } from '@material-ui/styles';
import { useState } from 'react';


const drawerWidth = 70;

const useStyle = makeStyles(theme => {
  return {
    root: {
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      overflow: 'hidden',
      '& .MuiToolbar-root': {
        boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;'
      },
      '& .MuiCard-root': {
        boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',
        transition: 'all ease-out 0.2s',
        [theme.breakpoints.down('xs')]: {
          margin: '0 50px'
        },

        '&:hover': {
          transform: 'rotateZ(-1.5deg) scale(1.1)',
          boxShadow: '3px 5px 7px rgba(0, 0, 0, 0.2)',
          transition: 'all ease-out 0.2s',
          [theme.breakpoints.down('md')]: {
            transform: 'none',
            boxShadow: '3px 5px 7px rgba(0, 0, 0, 0.2)',
          }
        }
      }
    },
    page: {
      background: '#f9fbfd',
      width: '100%',
      padding: theme.spacing(1)
    },

    appBar: {
      width: `calc(100% - ${drawerWidth}px)`,
      marginLeft: drawerWidth,
      [theme.breakpoints.down('sm')]: {
        width: '100%',
        backgroundColor: '#162276'
      }
    },


    drawer: {
      width: drawerWidth,
      [theme.breakpoints.down('sm')]: {
        display: 'none'
      }
    },
    drawerPaper: {
      width: drawerWidth,
      background: '#162276',
      color: 'white'
    },
    drawerHeader: {
      display: 'flex',
      alignItems: 'center',
      padding: theme.spacing(0, 1),
      // necessary for content to be below app bar
      ...theme.mixins.toolbar,
      justifyContent: 'center'
    },
    mobileDrawer: {
      width: '100vw'
    },


    toolbar: theme.mixins.toolbar,
    title: {
      flexGrow: '1'
    },
    lists: {
      marginTop: '10px'
    },
    fullList: {
      width: 'auto',
    },
    center: {
      textAlign: 'center'
    },
    menu: {
      marginTop: theme.spacing(5)
    }
  }
});



export default function Layout({ children }) {
  const classes = useStyle()
  const [anchor, setAnchor] = useState(null)
  const [openDrawer, setOpenDrawer] =useState(false)

  const openMenu = (event) => {
    setAnchor(event.currentTarget)
  }

  const closeMenu = () => {
    setAnchor(null)
  }

  const studentSideLinks = [
    {
      text: 'Dashboard',
      icon: <Tooltip title='Dasboard' placement='right-start' ><ViewModule color='error' /></Tooltip>,
      path: '/studentDashboard',
      id: 1
    },
    {
      text: 'Join/Create',
      icon: <Tooltip title='Join/Create' ><AddCircle color='error' /></Tooltip>,
      path: '/studentDashboard',
      id: 3
    },
  ]

  return (
    <div className={classes.root}>
      {/* // appbar */}

      <AppBar className={classes.appBar} position='fixed' color='inherit' elevation={0}>
        <Toolbar>

        <IconButton onClick={() => setOpenDrawer(true)}>
               <MenuRounded color='error' />
          </IconButton>

          <Drawer anchor='left' open={openDrawer} onClose={() => setOpenDrawer(false)} >
              <Box className={classes.mobileDrawer} role='presentation' textAlign='center' >
              <List>
          {studentSideLinks.map((links) => (
            <ListItem button key={links.id}>
              <ListItemText className={classes.center} primary={links.icon} />
            </ListItem>
          ))}
        </List>
              </Box>
          </Drawer>

          <Menu elevation={2} className={classes.menu} open={Boolean(anchor)} anchorEl={anchor} onClose={closeMenu} keepMounted >
            <MenuItem >Manage Account</MenuItem>
            <MenuItem >Settings</MenuItem>
            <MenuItem >Sign Out</MenuItem>
          </Menu>

          <div className={classes.title}></div>

          <IconButton>
              <Avatar src={phil} />
          </IconButton>

          <Hidden mdDown>
            <Typography variant='caption'>
              Cris Philip V. Cajurao
              <IconButton onClick={openMenu}>
                <ExpandMore />
              </IconButton>
            </Typography>
          </Hidden>
        </Toolbar>
      </AppBar>

      {/* sidebar */}
      <Drawer
        className={classes.drawer}
        variant="permanent"
        anchor="left"
        classes={{ paper: classes.drawerPaper }}
      >


        <List>
          {studentSideLinks.map((links) => (
            <ListItem button key={links.id}>
              <ListItemText className={classes.center} primary={links.icon} />
            </ListItem>
          ))}
        </List>

      </Drawer>

      <div
        className={classes.content}
      >
        <div className={classes.drawerHeader} />
        <div className={classes.page}>
          <div className={classes.toolbar} elevation={0}></div>
          {children}
        </div>
      </div>
    </div>
  )
}
